import{_ as r,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"64. Personal Carer S Leave","description":"","frontmatter":{"title":"64. Personal Carer S Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","personal-leave","employment"]},"headers":[],"relativePath":"ebas/mspp/leave/64-personal-carer-s-leave.md","filePath":"ebas/mspp/leave/64-personal-carer-s-leave.md"}'),n={name:"ebas/mspp/leave/64-personal-carer-s-leave.md"};function s(i,e,l,p,h,c){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_64-personal-carer-s-leave" tabindex="-1">64. Personal Carer S Leave <a class="header-anchor" href="#_64-personal-carer-s-leave" aria-label="Permalink to &quot;64. Personal Carer S Leave&quot;">​</a></h1><p><strong>64.1</strong> Additional schedules Provisions additional to those prescribed by this clause apply at the following Health Services and are contained in the following schedules:</p><p><strong>a.</strong> <a href="/eba/ebas/mspp/schedules/4-alfred-health-general-conditions.html">Schedule 4</a> Alfred Health</p><p><strong>b.</strong> <a href="/eba/ebas/mspp/schedules/8-royal-women-s-hospital-royal-children-s-hospital-general-emp.html">Schedule 8</a> Royal Women’s Hospital and Royal Children’s Hospital</p><p><strong>c.</strong> <a href="/eba/ebas/mspp/schedules/10-st-vincent-s-health-melbourne-ltd-general-conditions-agreeme.html">Schedule 10</a> St. Vincent’s Health The provisions of this clause apply to full-time and part-time Employees.</p><p><strong>64.2</strong> Definitions</p><p><strong>a.</strong> The term immediate family includes:</p><p><strong>(i)</strong> spouse (including a former spouse, a de facto partner and a former de facto partner) of the Employee. A de facto partner means a person who, although not legally married to the Employee, lives with the Employee in a relationship as a couple on a genuine domestic basis (whether the Employee and the person are of the same sex or different sexes); and</p><p><strong>(ii)</strong> child or an adult child (including an adopted child, a step child or an ex-nuptial child), parent, grandparent, grandchild or sibling of the Employee or spouse of the Employee.</p><p><strong>b.</strong> The hourly rate for Personal/Carer’s Leave purposes shall include Higher Qualification Allowances and over-Agreement payments – where a component of ordinary pay – where applicable.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>64.3</strong> Amount Of Paid Personal/Carer’s Leave</p><p><strong>a.</strong> Paid personal/carer’s leave is available to an Employee, when they are absent:</p><p><strong>(i)</strong> due to personal illness or injury; or</p><p><strong>(ii)</strong> for the purposes of caring for an immediate family or household member who is sick and requires the Employee’s care or support or who requires care due to an unexpected emergency.</p><p><strong>b.</strong> A full-time Employee is entitled to the following amount of paid personal/carer’s leave, which accrues progressively and accumulates from year to year:</p><p><strong>(i)</strong> 121 hours and 36 minutes will be available in the first year of Service;</p><p><strong>(ii)</strong> 136 hours and 48 minutes will be available per annum in the second, third and fourth years of Service; or</p><p><strong>(iii)</strong> 190 hours will be available in the fifth and following years of Service. In this clause 64.3 ‘years of Service’ includes Recognised Prior Service for the purposes of determining an Employee’s rate of personal/carer’s leave accrual.</p><p><strong>c.</strong> Paid personal/carer’s leave applies on a pro rata basis for part time Employees.</p><p><strong>d.</strong> Where an Employee transfers to another hospital or health service covered by this Agreement, accumulated personal/carer’s leave to their credit up to a maximum of 2128 working hours shall be credited to them in their new employment as accumulated personal/carer’s leave. The hospital or health service may require an Employee to produce a written statement from their previous Employer specifying the amount of accumulated personal leave standing to their credit at the time of leaving that previous employment.</p><p><strong>e.</strong> An Employee may be absent through sickness for one day without furnishing evidence of such sickness on not more than three occasions in any one year of service.</p><p><strong>f.</strong> If the period during which an Employee takes paid personal/carer’s leave includes a day or part-day that is a public holiday in the place where the Employee is based for work purposes, the Employee is taken not to be on paid personal/carer’s leave on that public holiday, but will be entitled to the ordinary time public holiday payment as per the provisions of this Agreement.</p><p><strong>64.4</strong> Pharmacists Only</p><p><strong>a.</strong> Notwithstanding any other provision in this clause, a pharmacist who contracts an infectious disease in the course of their duties, and the same having been certified to by a medical practitioner approved by the institution shall receive full pay during the necessary period off duty up to but not exceeding a period of three months.</p><p><strong>b.</strong> Where a pharmacist transfers to another hospital or health service covered by the Agreement accumulated personal/carer’s leave to their credit shall be credited to them by their new Employer in accordance with a certificate issued by the previous Employer.</p><p><strong>64.5</strong> Personal Leave For Personal Injury Or Sickness</p><p><strong>a.</strong> An Employee is entitled to use the full amount of their Personal Leave entitlement including accrued leave for the purposes of personal illness or injury, subject to the conditions set out in this clause.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>b.</strong> If the full period of personal/carer’s leave is not taken in any year, such portion as is not taken shall be cumulative from year to year.</p><p><strong>64.6</strong> Carer’s Leave To Care For An Immediate Family Or Household Member An Employee is entitled to use the full amount of their Personal/Carer’s Leave entitlement, including accrued leave, each year to care for members of their immediate family or household who are sick and require care or support or who require care or support due to an unexpected emergency, subject to the conditions set out in this clause.</p><p><strong>64.7</strong> Evidence Supporting Claim</p><p><strong>a.</strong> The Employee must, if required by the Employer, establish by production of a certificate by a registered health practitioner or by statutory declaration, the illness or injury of the person concerned.</p><p><strong>b.</strong> The Employee must where practicable, give the Employer notice prior to the absence of the intention to take leave, the name of the person requiring care and their relationship to the Employee, the reasons for taking such leave and the estimated length of absence. If it is not practicable for the Employee to give prior notice of absence, the Employee must notify the Employer by telephone of such absence at the first opportunity on the day of the absence.</p><p><strong>c.</strong> When taking leave to care for members of their immediate family or household who require care due to an unexpected emergency, the Employee must, if required by the Employer, establish by production of documentation acceptable to the Employer or a statutory declaration, the nature of the emergency and that such emergency resulted in the person concerned requiring care by the Employee.</p><p><strong>64.8</strong> Unpaid Personal/Carer’s Leave Where an Employee has exhausted all paid personal/carer’s leave entitlements, they are entitled to take unpaid carer’s leave to care for members of their immediate family or household who are sick and require care and support or who require care due to an unexpected emergency. The Employer and the Employee shall agree on the period. In the absence of agreement, the Employee is entitled to take up to two days per occasion, provided the requirements of 64.7 are met.</p>',36)])])}const u=r(n,[["render",s]]);export{m as __pageData,u as default};
